class Solution:
    def countTriplets(self, arr):
        n = len(arr)
        count = 0
        for i in range(n):
            a = arr[i]
            for j in range(i + 1, n):
                b = 0
                for m in range(j, n):
                    b ^= arr[m]
                    if a == b:
                        count += 1
                a ^= arr[j]
        return count

solutions.python:
class Solution:
    def countTriplets(self, arr):
        n = len(arr)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] ^ arr[i]
        count = 0
        for i in range(n):
            for k in range(i + 1, n):
                if prefix[k + 1] ^ prefix[i] == 0:
                    count += k - i
        return count

