var countTriplets = function(arr) {
    const n = arr.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] ^ arr[i];
    let count = 0;
    for (let i = 0; i < n; i++) {
        for (let k = i + 1; k < n; k++) {
            if ((prefix[k + 1] ^ prefix[i]) === 0) count += k - i;
        }
    }
    return count;
};
